//! FFI declarations for zpico-sys
//!
//! This module defines the C API that zpico implements and the
//! platform FFI functions that Rust provides.
//!
//! # Header Generation
//!
//! The header `c/include/zpico.h` is automatically generated by cbindgen
//! during the build process (see `build.rs`).

use core::ffi::c_void;

// c_char is used in cbindgen stubs
#[cfg(cbindgen)]
use core::ffi::c_char;

// ============================================================================
// Protocol Constants
// ============================================================================

/// Size of Zenoh ID in bytes
pub const ZPICO_ZID_SIZE: usize = 16;

/// Size of RMW GID in bytes (for ROS 2 humble compatibility)
pub const ZPICO_RMW_GID_SIZE: usize = 16;

// ============================================================================
// Error Codes
// ============================================================================

/// Success
pub const ZPICO_OK: i32 = 0;
/// Generic error
pub const ZPICO_ERR_GENERIC: i32 = -1;
/// Configuration error
pub const ZPICO_ERR_CONFIG: i32 = -2;
/// Session error
pub const ZPICO_ERR_SESSION: i32 = -3;
/// Task creation error
pub const ZPICO_ERR_TASK: i32 = -4;
/// Invalid key expression
pub const ZPICO_ERR_KEYEXPR: i32 = -5;
/// Resource limit reached
pub const ZPICO_ERR_FULL: i32 = -6;
/// Invalid handle
pub const ZPICO_ERR_INVALID: i32 = -7;
/// Publish error
pub const ZPICO_ERR_PUBLISH: i32 = -8;
/// Query timeout
pub const ZPICO_ERR_TIMEOUT: i32 = -9;

// ============================================================================
// Callback Types
// ============================================================================

/// Callback function type for receiving samples (legacy, payload only).
///
/// # Parameters
/// * `data` - Pointer to received data buffer
/// * `len` - Length of data in bytes
/// * `ctx` - User-provided context pointer
pub type ZpicoCallback = extern "C" fn(data: *const u8, len: usize, ctx: *mut c_void);

/// Callback function type for receiving samples with attachment (RMW compatible).
///
/// # Parameters
/// * `data` - Pointer to received data buffer
/// * `len` - Length of data in bytes
/// * `attachment` - Pointer to attachment buffer (may be NULL)
/// * `attachment_len` - Length of attachment in bytes
/// * `ctx` - User-provided context pointer
pub type ZpicoCallbackWithAttachment = extern "C" fn(
    data: *const u8,
    len: usize,
    attachment: *const u8,
    attachment_len: usize,
    ctx: *mut c_void,
);

/// Notify callback for direct-write subscribers.
///
/// Called after the C shim has written the payload directly into the Rust
/// static buffer. Only provides the payload length and attachment data.
///
/// # Parameters
/// * `len` - Length of payload already written to the buffer
/// * `attachment` - Pointer to attachment buffer (may be NULL)
/// * `attachment_len` - Length of attachment in bytes
/// * `ctx` - User-provided context pointer
pub type ZpicoNotifyCallback =
    extern "C" fn(len: usize, attachment: *const u8, attachment_len: usize, ctx: *mut c_void);

/// Zero-copy callback: data pointer is borrowed from zenoh-pico's receive buffer.
/// Only valid during the callback invocation. Requires `unstable-zenoh-api` feature.
///
/// # Parameters
/// * `data` - Pointer to payload in zenoh-pico's internal buffer (borrowed, NOT owned)
/// * `len` - Length of payload in bytes
/// * `attachment` - Pointer to attachment buffer (may be NULL)
/// * `attachment_len` - Length of attachment in bytes
/// * `ctx` - User-provided context pointer
pub type ZpicoZeroCopyCallback = extern "C" fn(
    data: *const u8,
    len: usize,
    attachment: *const u8,
    attachment_len: usize,
    ctx: *mut c_void,
);

/// Callback function type for receiving queries (service requests).
///
/// # Parameters
/// * `keyexpr` - Key expression string (not null-terminated)
/// * `keyexpr_len` - Length of key expression
/// * `payload` - Pointer to request payload (may be NULL)
/// * `payload_len` - Length of payload in bytes
/// * `ctx` - User-provided context pointer
pub type ZpicoQueryCallback = extern "C" fn(
    keyexpr: *const core::ffi::c_char,
    keyexpr_len: usize,
    payload: *const u8,
    payload_len: usize,
    ctx: *mut c_void,
);

